#include<stdio.h>

int main()
{
    long int a,b,i,j,vla,val;
    scanf("%ld%ld",&a,&b);
    vla=a;
    val=b;

    if( b==1)
    {
        printf("Valera\n");
    }
    else
    {
        for(i=1,j=2;i>0,j>0;i=i+2,j=j+2)
        {
            vla=vla-i;

             if(vla<0)
            {
                printf("Vladik\n");
                goto end;
            }
            val=val-j;

            if(val<0)
            {
                printf("Valera\n");
                goto end;
            }
        }

    }
    end:
        return 0;

}

